  // fold `div(v, a) * b + rem(v, a)` to `div(v, a) * (b - a) + v`
  Value *DivOpV;
  APInt DivOpC;
  if (MatchDiv(MulOpV, DivOpV, DivOpC, IsSigned) && X == DivOpV && C0 == DivOpC) {
    if (MulOpC == C0)
      return X; 

    if (Rem->hasOneUse() && Mul && Mul->hasOneUse() && isGuaranteedNotToBePoison(X, nullptr, &I, nullptr)) {
      // The old optimization handles cases where `b` is a multiple of `a`.
      // The original issue requests optimization when `b > a`.
      // To avoid interfering with the other optimization, we only trigger when MulOpC is not a multiple of C0.
      if (MulOpC.urem(C0) != 0) {
        APInt Diff = MulOpC - C0;
        Value *DiffV = ConstantInt::get(I.getType(), Diff);
        Instruction *NewMulInst = cast<Instruction>(Builder.CreateMul(MulOpV, DiffV, "reass.mul"));

        if (Mul && Mul->getOpcode() == Instruction::Mul) {
            if (cast<OverflowingBinaryOperator>(Mul)->hasNoUnsignedWrap() && Diff.isNonNegative())
                NewMulInst->setHasNoUnsignedWrap(true);
        } else if (Mul && Mul->getOpcode() == Instruction::Shl) {
            if (cast<OverflowingBinaryOperator>(Mul)->hasNoUnsignedWrap() && Diff.isNonNegative())
                NewMulInst->setHasNoUnsignedWrap(true);
        }
        return Builder.CreateAdd(NewMulInst, X);
      }
    }
  }

  return nullptr;
}
CODEEOF

